INSERT OR REPLACE INTO sites (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('s-anthropic-claude', 'anthropic-claude', 'claude.ai', 'https://claude.ai', 'Claude', 'AI assistant by Anthropic, focused on safety and helpfulness.', 'Claude is the AI assistant that developers actually trust with their code. Where others optimize for impressive demos, Anthropic optimized for reliability and honesty. Claude Code (the CLI) turned it from a chatbot into a genuine engineering tool. The safety-first approach is not a handicap, it is the product.', 5, 'The AI you actually trust', 'AI / ML', 'Series C+', '$2B+', 2021, '500+', 'San Francisco', 'US', 'ai assistant,large language model,safety,developer tools', 'Google, Spark Capital, Salesforce Ventures, Menlo Ventures', '{"github": "https://github.com/anthropics", "twitter": "https://x.com/AnthropicAI", "linkedin": "https://linkedin.com/company/anthropic"}', 1, 'anthropic-claude.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now'));
INSERT OR REPLACE INTO sites (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('s-cal-com', 'cal-com', 'cal.com', 'https://cal.com', 'Cal.com', 'Open source scheduling infrastructure.', 'The open-source Calendly. What makes Cal.com interesting is not that it is open source, but that they proved open-source scheduling can be a real business. The self-hosted option is a wedge. The hosted version is the product.', 4, 'Open source done right', 'SaaS', 'Series A', '$25M', 2021, '30-50', 'San Francisco', 'US', 'scheduling,open source,calendar,productivity', 'Dick Costolo, Joseph Jacks (OSS Capital), Peer Richelsen', '{"github": "https://github.com/calcom/cal.com", "twitter": "https://x.com/calabordar", "linkedin": "https://linkedin.com/company/cal-com"}', 0, 'cal-com.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now'));
INSERT OR REPLACE INTO sites (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('s-cursor', 'cursor', 'cursor.com', 'https://cursor.com', 'Cursor', 'The AI-first code editor.', 'Cursor bet that the future of coding is not copilot-inside-VSCode but a ground-up rethinking of the editor. They were right. Tab completion that reads your mind, inline diffs that make sense, and a cmd-K that actually works. The VSCode fork approach was the right call: familiar enough to switch, different enough to stay.', 5, 'Changed how developers write code', 'AI / ML', 'Series B', '$400M', 2022, '50-100', 'San Francisco', 'US', 'ai,code editor,developer tools,productivity', 'Andreessen Horowitz, Thrive Capital, OpenAI Startup Fund', '{"github": "https://github.com/getcursor", "twitter": "https://x.com/cursor_ai", "linkedin": "https://linkedin.com/company/cursor-ai"}', 1, 'cursor.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now'));
INSERT OR REPLACE INTO sites (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('s-eleven-labs', 'eleven-labs', 'elevenlabs.io', 'https://elevenlabs.io', 'ElevenLabs', 'AI voice generation and speech synthesis platform.', 'ElevenLabs makes voice cloning feel like magic. Upload 30 seconds of audio, get a voice that sounds real. The ethical implications are enormous and they know it. What is interesting is the business: audiobooks, dubbing, accessibility tools. Not a toy. A platform.', 4, 'Voice AI that actually sounds human', 'AI / ML', 'Series B', '$80M', 2022, '50-100', 'New York', 'US', 'voice ai,speech synthesis,text to speech,artificial intelligence', 'Andreessen Horowitz, Nat Friedman, Daniel Gross', '{"github": "https://github.com/elevenlabs", "twitter": "https://x.com/elevenlabsio", "linkedin": "https://linkedin.com/company/elevenlabs"}', 0, 'eleven-labs.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now'));
INSERT OR REPLACE INTO sites (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('s-linear', 'linear', 'linear.app', 'https://linear.app', 'Linear', 'Issue tracking built for modern software teams.', 'Linear is what happens when someone with taste builds project management. Every interaction feels considered. The keyboard shortcuts alone are worth the switch. In a market drowning in feature-bloated tools, Linear chose speed and focus. That bet paid off.', 5, 'Defined a new standard for dev tools', 'DevTools', 'Series B', '$35M', 2019, '50-100', 'San Francisco', 'US', 'project management,issue tracking,developer tools,productivity', 'Sequoia Capital, 01 Advisors, SV Angel', '{"github": "https://github.com/linear", "twitter": "https://x.com/linear", "linkedin": "https://linkedin.com/company/linear"}', 1, 'linear.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now'));
INSERT OR REPLACE INTO sites (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('s-perplexity', 'perplexity', 'perplexity.ai', 'https://perplexity.ai', 'Perplexity', 'AI-powered answer engine that searches the web.', 'Perplexity did what Google should have done five years ago: just answer the question. The product is deceptively simple. You ask, it answers with sources. No ten blue links, no ads above the fold. Whether this replaces Google search or becomes a power-user tool is the billion dollar question.', 5, 'The Google killer that might actually be', 'AI / ML', 'Series B', '$73.6M', 2022, '100-200', 'San Francisco', 'US', 'ai search,answer engine,web search,artificial intelligence', 'IVP, NEA, Databricks Ventures, Jeff Bezos', '{"twitter": "https://x.com/perabordar", "linkedin": "https://linkedin.com/company/perplexity-ai"}', 1, 'perplexity.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now'));
INSERT OR REPLACE INTO sites (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('s-resend', 'resend', 'resend.com', 'https://resend.com', 'Resend', 'Email API for developers. Beautiful, simple, reliable.', 'Resend took the most annoying part of building a product (transactional email) and made it pleasant. The DX is absurdly good. React Email as a companion project shows they understand that email is a design problem, not just an infrastructure one.', 4, 'DX that makes you jealous', 'DevTools', 'Series A', '$3.5M', 2022, '10-30', 'San Francisco', 'US', 'email,api,developer tools,transactional email', 'Y Combinator, SV Angel, Dylan Field', '{"github": "https://github.com/resend", "twitter": "https://x.com/resabordar", "linkedin": "https://linkedin.com/company/resend"}', 1, 'resend.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now'));
INSERT OR REPLACE INTO sites (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('s-supabase', 'supabase', 'supabase.com', 'https://supabase.com', 'Supabase', 'The open source Firebase alternative.', 'Supabase proved that Postgres is the answer to most backend questions. Auth, storage, realtime, edge functions... all built on Postgres. The developer experience is what makes it special: instant APIs, a dashboard that does not suck, and documentation that reads like a tutorial.', 4, 'Postgres as a platform', 'DevTools', 'Series C+', '$116M', 2020, '100-200', 'Singapore', 'Global / Remote', 'database,open source,backend,postgres,firebase alternative', 'Felicis Ventures, Coatue Management, Y Combinator', '{"github": "https://github.com/supabase", "twitter": "https://x.com/supabase", "linkedin": "https://linkedin.com/company/supabase"}', 0, 'supabase.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now'));
INSERT OR REPLACE INTO sites (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('s-val-town', 'val-town', 'val.town', 'https://val.town', 'Val Town', 'Social website and API for writing and running code.', 'Val Town is the most interesting thing happening in developer tools right now. A social network where the content is running code. Every val is a URL. Every function is deployable. It feels like what GitHub Gists should have become.', 4, 'Code as social media', 'DevTools', 'Seed', '$5.5M', 2022, '5-10', 'Brooklyn', 'US', 'social coding,serverless,developer tools,code sharing', 'Sequoia Capital Scout, Craft Ventures, Tom Preston-Werner', '{"github": "https://github.com/val-town", "twitter": "https://x.com/valabordar", "linkedin": "https://linkedin.com/company/val-town"}', 0, 'val-town.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now'));
INSERT OR REPLACE INTO sites (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('s-vercel', 'vercel', 'vercel.com', 'https://vercel.com', 'Vercel', 'Frontend cloud platform for deploying web applications.', 'Vercel made deployment a non-event. Push code, get a URL. That simplicity is their moat. The Next.js connection gives them an unfair advantage: they build the framework AND the best place to deploy it. Love it or question the vendor lock-in, the DX is undeniably best-in-class.', 4, 'Made deployment boring (compliment)', 'DevTools', 'Series C+', '$250M', 2015, '300+', 'San Francisco', 'US', 'deployment,frontend,cloud platform,next.js,developer tools', 'Accel, GV (Google Ventures), Bedrock Capital, Greenoaks', '{"github": "https://github.com/vercel", "twitter": "https://x.com/vercel", "linkedin": "https://linkedin.com/company/vercel"}', 0, 'vercel.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now'));

